module.exports = /*#__PURE__*/JSON.parse('[{"step":"01","title":"Find someone who\'s done it before.","body":"Search by category, browse curated picks, or follow a share link from a professional you know. Every listing carries real ratings + a verified credentials badge."},{"step":"02","title":"Pay once. Money sits in escrow.","body":"Pick a slot, pay with card or bank transfer. Your money is held until the call is delivered — no subscriptions, no hidden fees, no recurring anything."},{"step":"03","title":"Talk. Get paid. Or get refunded.","body":"Join with one tap when it\'s call time. The professional gets paid the moment it ends. If they don\'t show up, you get every naira back, automatically."}]');

